export type Breakpoints = Record<string, `${number}px`>;
/**
 * This custom hook returns the current breakpoint based on the width of a container, which is a DOM object, "exclusive" meaning only the breakpoint matching the container width will be returned.
 * The breakpoints are returned as a set of boolean values keyed to each breakpoint.
 */
export declare function useContainerBreakpointsExclusive(breakpoints?: Breakpoints): {
    breakpointMatches: Record<string, boolean>;
    ref: (node: HTMLElement) => void;
};
